<table class="sortable" id="tunings"><input type="text" id="filter" class="inputs" onkeyup="filter()" placeholder="Filter"><thead><tr><th width="10%" class="name"><button>Strings<span aria-hidden="true"></span></button></th><th width="12%" class="name"><button>Name<span aria-hidden="true"></span></button></th><th width="20%" ><button>Tuning<span aria-hidden="true"></span></button></th><th width="16%" ><button>Degrees<span aria-hidden="true"></span></button></th><th width="16%" ><button>Unique Degrees<span aria-hidden="true"></span></button></th><th width="26%" ><button>Notes<span aria-hidden="true"></span></button></th></tr></thead><tbody><?php $tun_url = $self.$x['url_k'].$x['url_y'].$x['url_z'].$x['url_s'].$x['url_hl'];foreach ( $tunings as $key => $value ) {$add_url = "&x=".$value['url_notes'];echo "<tr><td id=\"pad\" class=\"name\">".$value['strs']."-String</td><td id=\"pad\" class=\"name\"><a href=\"".$tun_url.$add_url."\">".$value['name']."</a></td><td id=\"pad\"><a href=\"".$tun_url.$add_url."\">".$value[$rev.'notes']."</a></td><td id=\"pad\">".$value[$rev.'dgs']."</td><td id=\"pad\">".str_replace("1 3 5", "(1 3 5)",str_replace("1 ♭3 5", "(1 ♭3 5)",$value['udgs']))."</td><td id=\"pad\">".$value['info']."</td></tr>";} ?></tbody></table>